UPDATE TB_POPUP_MANAGE SET POPUP_SJ_NM = #{popupTitleNm}, FILE_URL = #{fileUrl},
       POPUP_VRTICL_LC = #{popupHlc}, POPUP_WIDTH_LC = #{popupWlc}, POPUP_VRTICL_SIZE = #{popupHSize}, POPUP_WIDTH_SIZE = #{popupWSize},
       NTCE_BGNDE = #{ntceBgnde}, NTCE_ENDDE = #{ntceEndde}, STOPVEW_SETUP_AT = #{stopVewAt}, NTCE_AT = #{ntceAt},
       LAST_UPDT_PNTTM = CURRENT_TIMESTAMP, LAST_UPDUSR_ID = #{lastUpdusrId}
WHERE POPUP_ID = #{popupId}
